async update(updateSysRoleDto: UpdateSysRoleDto) {
  return await this.prisma.$transaction(async (prisma) => {
    const { roleId, roleKey } = updateSysRoleDto;
    const role = await prisma.sysRole.findUnique({
      where: {
        delFlag: '0',
        roleId,
      },
    });
    if (!role) throw new ApiException('该记录不存在，请重新查询后操作。');
    const role2 = await prisma.sysRole.findFirst({
      where: {
        delFlag: '0',
        roleKey,
        roleId: {
          not: roleId,
        },
      },
    });
    if (role2) throw new ApiException('权限字符已存在，请更换后再试。');
    const params: AddSysRoleDto = JSON.parse(
      JSON.stringify(updateSysRoleDto),
    );
    delete params.menuIds;
    await prisma.sysRole.update({
      data: {
        ...params,
        menus: {
          set: updateSysRoleDto.menuIds.map((menuId) => ({ menuId })),
        },
      },
      where: {
        roleId,
      },
    });
    return await this.addRuleUserPv(roleId);
  });
}

async operLogList(
  reqOperLogDto: ReqOperLogDto,
): Promise<PaginatedDto<OperLog>> {
  const where: FindOptionsWhere<OperLog> = {};
  if (reqOperLogDto.title) {
    where.title = Like(`%${reqOperLogDto.title}%`);
  }
  if (reqOperLogDto.operName) {
    where.operName = Like(`%${reqOperLogDto.operName}%`);
  }
  if (reqOperLogDto.businessType) {
    where.businessType = reqOperLogDto.businessType;
  }
  if (reqOperLogDto.status) {
    where.status = reqOperLogDto.status;
  }
  if (reqOperLogDto.params) {
    where.operTime = Between(
      reqOperLogDto.params.beginTime,
      moment(reqOperLogDto.params.endTime).add(1, 'day').format(),
    );
  }
  const queryBuilder = this.operLogRepository
    .createQueryBuilder('operLog')
    .where(where);
  if (reqOperLogDto.orderByColumn) {
    //后端排序
    const order = reqOperLogDto.isAsc === 'descending' ? 'DESC' : 'ASC';
    queryBuilder.orderBy(`operLog.${reqOperLogDto.orderByColumn}`, order);
  }
  const result = await queryBuilder
    .addOrderBy('operLog.operTime', 'DESC')
    .skip(reqOperLogDto.skip)
    .take(reqOperLogDto.take)
    .getManyAndCount();
  return {
    rows: result[0],
    total: result[1],
  };
}

async presignPutItemPart(
    { key, size, uploadId, partNumber }: AwsS3PresignPartRequestDto,
    options?: IAwsS3PresignPutItemPartOptions
): Promise<AwsS3PresignPartDto | null> {
    if (!this.isInitialized()) {
        this.logger.warn(
            'AWS S3 credentials not configured. S3 functionalities will be disabled.'
        );

        return null;
    }

    if (key.startsWith('/')) {
        throw new Error('Key should not start with "/"');
    }

    const config = this.config.get(
        options?.access ?? EnumAwsS3Accessibility.public
    );

    const uploadPartCommand: UploadPartCommand = new UploadPartCommand({
        Bucket: config.bucket,
        Key: key,
        PartNumber: partNumber,
        UploadId: uploadId,
    });

    const { extension, mime } = this.getFileInfoFromKey(key);
    const expiresIn = options?.expired ?? this.presignExpired;
    const presignUrl = await getSignedUrl(
        this.s3Client,
        uploadPartCommand,
        {
            expiresIn,
        }
    );

    return {
        expiredIn: expiresIn,
        presignUrl: presignUrl,
        key,
        partNumber,
        mime,
        extension,
        size,
    };
}

