updateEventTriggerMetaV3 = (
  moduleConfig: HasuraModuleConfig,
  eventHandlerConfigs: TrackedHasuraEventHandlerConfig[],
) => {
  const { managedMetaDataConfig } = moduleConfig;

  if (!managedMetaDataConfig) {
    throw new Error(MISSING_META_CONFIG);
  }

  const defaultRetryConfig =
    managedMetaDataConfig.defaultEventRetryConfig ?? defaultHasuraRetryConfig;

  eventHandlerConfigs.forEach((config) => {
    const { schema = 'public', databaseName = 'default', tableName } = config;

    const tableYamlPath = `${managedMetaDataConfig.dirPath}/databases/${databaseName}/tables/${schema}_${tableName}.yaml`;
    const tableMeta = readFileSync(tableYamlPath, utf8);
    const tableEntry = load(tableMeta) as TableEntry;

    tableEntry.event_triggers = mergeEventHandlerConfig(
      config,
      moduleConfig,
      defaultRetryConfig,
      tableEntry,
    );

    const yamlString = dump(tableEntry);
    writeFileSync(tableYamlPath, yamlString, utf8);
  });
}

async find(query: TagQueryDto): Promise<PageDto<TagDto>> {
  const { limit, offset } = QueryDto.getPageable(query);

  const tagQuery = this.tagRepo.createQueryBuilder('tag');

  const count = await tagQuery.getCount();

  if (query.includePostCount) {
    tagQuery
      .addSelect('COUNT(post_tag.tagId) AS tag_post_count')
      .leftJoin(PostTagEntity, 'post_tag', 'tag.id = post_tag.tagId')
      .groupBy('tag.id')
      .addGroupBy('tag.name')
      .addGroupBy('tag.slug');
  }

  if (query.name) {
    tagQuery.where('LOWER(tag.name) LIKE LOWER(:name)', {
      name: `%${query.name}`,
    });
  }

  tagQuery.orderBy('tag.createdAt', 'DESC').offset(offset).limit(limit);

  const { entities, raw } = await tagQuery.getRawAndEntities();

  return PageDto.from({
    list: entities.map((e, i) => {
      const dto = e.toDto();
      if (query.includePostCount) {
        dto.postCount = raw[i]['tag_post_count'];
      }
      return dto;
    }),
    count: count,
    offset: offset,
    limit: limit,
  });
}

async (em) => {
  const firstLesson = await em
    .createQueryBuilder(LessonEntity, 'lesson')
    .leftJoin('lesson.chapter', 'chapter')
    .where('chapter.course_id = :courseId', { courseId })
    .andWhere('chapter.id != :chapterId', { chapterId })
    .orderBy('chapter.sortOrder', 'ASC')
    .addOrderBy('lesson.sortOrder', 'ASC')
    .limit(1)
    .getOne();

  await em
    .createQueryBuilder(EnrolledCourseEntity, 'ec')
    .innerJoin('ec.resumeLesson', 'lesson')
    .where('ec.courseId = :courseId', { courseId })
    .andWhere('lesson.chapter_id = :chapterId', { chapterId })
    .getMany()
    .then((entities) => {
      if (entities.length === 0) return;
      return em.update(
        EnrolledCourseEntity,
        {
          courseId: courseId,
          userId: In(entities.map((en) => en.userId)),
        },
        {
          resumeLesson: firstLesson ? { id: firstLesson.id } : null,
        },
      );
    });

  await em.delete(ChapterEntity, {
    id: chapterId,
  });
}

async batchDeleteAccountByIdListApi(
  idList: number[],
  currentUser: ICurrentUserType
): Promise<string> {
  const { id: accountId } = currentUser;
  // TODO 判断不能删除自己及下面有账号的
  if (idList.includes(accountId)) {
    throw new HttpException('自己不能删除自己', HttpStatus.OK);
  }
  const accountEntityList: Pick<AccountEntity, 'id'>[] = await this.accountRepository.find({
    where: { parentId: In(idList) },
    select: ['id'],
  });
  if (accountEntityList.length) {
    throw new HttpException('下面有子账号不能直接删除', HttpStatus.OK);
  }
  // 超管不能被删除
  const accountEntityList1: Pick<AccountEntity, 'accountType'>[] =
    await this.accountRepository.find({ where: { id: In(idList) }, select: ['accountType'] });
  if (
    accountEntityList1.length &&
    accountEntityList1
      .map((item) => item.accountType)
      .some((item) => item == AccountTypeEnum.SUPER_ACCOUNT)
  ) {
    throw new HttpException('超管不能被删除', HttpStatus.OK);
  }
  const { affected } = await this.accountRepository.softDelete(idList);
  if (affected) {
    return '删除成功';
  } else {
    return '删除失败';
  }
}

function updateJestConfig(
  jestOptions: Record<string, any>,
  options: LibraryOptions,
  packageKey: string,
  distRoot: string,
) {
  if (!jestOptions) {
    return;
  }
  if (jestOptions.rootDir === DEFAULT_PATH_NAME) {
    jestOptions.rootDir = '.';
    jestOptions.coverageDirectory = './coverage';
  }
  const defaultSourceRoot =
    options.rootDir !== undefined ? options.rootDir : DEFAULT_LIB_PATH;

  const jestSourceRoot = `<rootDir>/${defaultSourceRoot}/`;
  if (!jestOptions.roots) {
    jestOptions.roots = ['<rootDir>/src/', jestSourceRoot];
  } else if (jestOptions.roots.indexOf(jestSourceRoot) < 0) {
    jestOptions.roots.push(jestSourceRoot);
  }

  if (!jestOptions.moduleNameMapper) {
    jestOptions.moduleNameMapper = {};
  }
  const packageRoot = join('<rootDir>' as Path, distRoot);
  const newMapper = createModuleNameMapper(packageKey, packageRoot);
  Object.assign(jestOptions.moduleNameMapper, newMapper);

  inPlaceSortByKeys(jestOptions.moduleNameMapper);
}

paginate =
    <T extends IProps<any, any, any, any, any>>(props: T) =>
    (spec: {
      where: IProps.DeduceWhere<T>;
      orderBy: IProps.DeduceOrderBy<T>[];
    }) =>
    async (input: IPage.IRequest): Promise<IPage<IProps.DeduceOutput<T>>> => {
      input.limit ??= 100;

      const records: number = await props.schema.count({
        where: spec.where,
      });
      const pages: number =
        input.limit !== 0 ? Math.ceil(records / input.limit) : 1;
      input.page = input.page ? Math.max(1, Math.min(input.page, pages)) : 1;

      const data: IProps.DeduceRaw<T>[] = await props.schema.findMany({
        ...props.payload,
        skip: (input.page - 1) * input.limit,
        take: input.limit || records,
        where: spec.where,
        orderBy: spec.orderBy,
      });
      return {
        data: await ArrayUtil.asyncMap(data, async (elem) =>
          props.transform(elem),
        ),
        pagination: {
          records,
          pages,
          current: input.page,
          limit: input.limit,
        },
      };
    }

async (partial) => {
  partial.mode ??= await select("mode")("Migration mode")(
    ["NestJS" as "nest", "SDK" as "sdk"],
    (value) => (value === "NestJS" ? "nest" : "sdk"),
  );
  partial.input ??= await input("input")("Swagger file location");
  partial.output ??= await input("output")("Response directory path");
  partial.package ??= await input("package")("Package name");
  partial.keyword ??=
    (await select("keyword")("Keyword parameter mode")([
      "true",
      "false",
    ])) === "true";

  if (partial.keyword)
    partial.keyword = (partial.keyword as any) === "true";
  else
    partial.keyword =
      (await select("keyword")("Keyword parameter mode")([
        "true",
        "false",
      ])) === "true";
  if (partial.simulate)
    partial.simulate = (partial.simulate as any) === "true";
  else
    partial.simulate =
      (await select("simulate")("Mokup Simulator")(["true", "false"])) ===
      "true";

  if (partial.e2e) partial.e2e = (partial.e2e as any) === "true";
  else
    partial.e2e =
      (await select("e2e")("Generate E2E tests")(["true", "false"])) ===
      "true";
  return partial as IOutput;
}

public nest(config: INestiaMigrateConfig): Record<string, string> {
  const context: INestiaMigrateContext = createContext(
    "nest",
    this.data_,
    config,
  );
  const files: Record<string, string> = {
    ...Object.fromEntries(
      Object.entries(NEST_TEMPLATE).filter(
        ([key]) =>
          key.startsWith("src/api/structures") === false &&
          key.startsWith("src/api/functional") === false &&
          key.startsWith("src/api/controllers") === false &&
          key.startsWith("test/features") === false,
      ),
    ),
    ...NestiaMigrateNestProgrammer.write(context),
    ...NestiaMigrateApiProgrammer.write(context),
    ...(config.e2e ? NestiaMigrateE2eProgrammer.write(context) : {}),
    ...(config.keyword === false
      ? {
          "nestia.config.ts": NEST_TEMPLATE["nestia.config.ts"]!.replace(
            "keyword: true",
            "keyword: false",
          ),
        }
      : {}),
  };
  return config.package ? renameSlug(config.package, files) : files;
}

schemaVisitor: SchemaVisitor = (schema: any): SchemaObject => {
  if (
    schema.hasOwnProperty("type") &&
    schema["type"] === "string" &&
    schema.hasOwnProperty("contentEncoding")
  ) {
    if (schema["contentEncoding"] === "base64") {
      if (schema.hasOwnProperty("format")) {
        if (schema["format"] === "byte") {
          this.log(
            `Deleted schema contentEncoding: base64 (leaving format: byte)`,
          );
          delete schema["contentEncoding"];
        } else {
          this.error(
            `Unable to down-convert schema contentEncoding: base64 to format: byte because the schema already has a format (${schema["format"]})`,
          );
        }
      } else {
        delete schema["contentEncoding"];
        schema["format"] = "byte";
        this.log(
          `Converted schema: 'contentEncoding: base64' to 'format: byte'`,
        );
      }
    } else {
      this.error(
        `Unable to down-convert contentEncoding: ${schema["contentEncoding"]}`,
      );
    }
  }
  return this.walkNestedSchemaObjects(schema, schemaVisitor);
}

write_type_tag_matrix =
    (importer: ImportDictionary) =>
    (
      from: "array" | "boolean" | "number" | "bigint" | "string" | "object",
      base: ts.TypeNode,
      matrix: IMetadataTypeTag[][],
    ): ts.TypeNode => {
      matrix = matrix.filter((row) => row.length !== 0);
      if (matrix.length === 0) return base;
      else if (matrix.length === 1)
        return ts.factory.createIntersectionTypeNode([
          base,
          ...matrix[0]!.map((tag) =>
            SdkTypeTagProgrammer.write(importer, from, tag),
          ),
        ]);
      return ts.factory.createIntersectionTypeNode([
        base,
        ts.factory.createUnionTypeNode(
          matrix.map((row) =>
            row.length === 1
              ? SdkTypeTagProgrammer.write(importer, from, row[0]!)
              : ts.factory.createIntersectionTypeNode(
                  row.map((tag) =>
                    SdkTypeTagProgrammer.write(importer, from, tag),
                  ),
                ),
          ),
        ),
      ]);
    }

